import React, { useState, useRef, useEffect } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { FiMenu, FiX, FiChevronDown, FiUser, FiUsers } from 'react-icons/fi';

const API = import.meta.env.VITE_API_URL || "http://localhost:5000";

const Navigation = () => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [teacher, setTeacher] = useState(null);
  const [isProfileOpen, setIsProfileOpen] = useState(false);
  const [isEvalOpen, setIsEvalOpen] = useState(false);

  const profileRef = useRef(null);
  const evalRef = useRef(null);

  const location = useLocation();
  const navigate = useNavigate();

  const isActive = (path) => location.pathname === path;

  const isEvalActive =
    location.pathname === '/evaluate' ||
    location.pathname === '/EvaluateBatch';

  // ✅ Fetch logged-in teacher
  useEffect(() => {
    const fetchTeacher = async () => {
      const token = localStorage.getItem("token");

      if (!token) return;

      try {
        const res = await fetch(`${API}/api/me`, {
          headers: {
            "Content-Type": "application/json",
            Authorization: `Bearer ${token}`,
          },
        });

        if (!res.ok) throw new Error("Not authorized");

        const data = await res.json();
        setTeacher(data);

      } catch (err) {
        console.log("Teacher fetch error:", err);
        setTeacher(null);
      }
    };

    fetchTeacher();
  }, []);

  // close dropdowns
  useEffect(() => {
    const handler = (e) => {
      if (profileRef.current && !profileRef.current.contains(e.target)) {
        setIsProfileOpen(false);
      }
      if (evalRef.current && !evalRef.current.contains(e.target)) {
        setIsEvalOpen(false);
      }
    };

    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  const handleLogout = () => {
    localStorage.removeItem("token");
    setTeacher(null);
    navigate("/");
  };

  const handleMobileClose = () => {
    setIsMobileMenuOpen(false);
    setIsEvalOpen(false);
  };

  return (
    <nav className="navbar">
      <div className="navbar-container">

        {/* Logo */}
        <Link to="/" className="navbar-logo">
          📝 AI Examiner
        </Link>

        {/* Mobile Toggle */}
        <button onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}>
          {isMobileMenuOpen ? <FiX /> : <FiMenu />}
        </button>

        <ul className={`nav-menu ${isMobileMenuOpen ? 'active' : ''}`}>

          <li className="nav-item">
            <Link to="/" className={`nav-link ${isActive('/') ? 'active' : ''}`}>
              Home
            </Link>
          </li>

          {/* Logged in menu */}
          {teacher && (
            <>
              <li className="nav-item">
                <Link to="/dashboard" className="nav-link">Dashboard</Link>
              </li>

              <li className="nav-item">
                <Link to="/management" className="nav-link">Management</Link>
              </li>

              <li className="nav-item">
                <Link to="/history" className="nav-link">History</Link>
              </li>

              {/* Evaluate */}
              <li className="nav-item" ref={evalRef}>
                <button onClick={() => setIsEvalOpen(!isEvalOpen)}>
                  Evaluate Now <FiChevronDown />
                </button>

                {isEvalOpen && (
                  <div className="dropdown">
                    <button onClick={() => navigate('/evaluate')}>
                      <FiUser /> Single Student
                    </button>

                    <button onClick={() => navigate('/EvaluateBatch')}>
                      <FiUsers /> Batch
                    </button>
                  </div>
                )}
              </li>
            </>
          )}

          {/* Login */}
          {!teacher && (
            <li>
              <button onClick={() => navigate("/login")}>
                Login
              </button>
            </li>
          )}

          {/* Profile */}
          {teacher && (
            <li ref={profileRef}>
              <div onClick={() => setIsProfileOpen(!isProfileOpen)}>
                👤 {teacher?.email}
              </div>

              {isProfileOpen && (
                <div className="dropdown">
                  <p>{teacher?.email}</p>

                  <button onClick={() => navigate("/settings")}>
                    Settings
                  </button>

                  <button onClick={handleLogout}>
                    Logout
                  </button>
                </div>
              )}
            </li>
          )}

        </ul>
      </div>
    </nav>
  );
};

export default Navigation;
